// Helper: get answer letters (A, B, C...) for display
function getAnswerLetters(question) {
  return question.ans.map(i => String.fromCharCode(65 + i)).join(', ');
}

// Helper: get answer texts
function getAnswerTexts(question) {
  return question.ans.map(i => question.opts[i]);
}
